import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const StaffManager = () => {
  const { user } = useAuth(); // Lấy user đang đăng nhập để check quyền
  const { staffList, addStaff, deleteStaff, updatePassword, promoteStaff, toggleStaffStatus } = useData();

  const [formData, setFormData] = useState({ name: '', username: '', password: '' });

  // Chỉ Chief Admin mới có quyền quản lý tài khoản (Thêm/Xóa/Đình chỉ/Bổ nhiệm)
  const isChief = user?.role === 'chief_admin';

  const handleAdd = (e) => {
    e.preventDefault();
    if (!isChief) return alert("Bạn không có quyền tạo nhân sự!");
    if (!formData.name || !formData.username || !formData.password) return;
    addStaff({ ...formData });
    setFormData({ name: '', username: '', password: '' });
    alert("Đã tạo tài khoản thành công (Mặc định là Staff)");
  };

  const handleDelete = (id) => {
    if (window.confirm("Bạn có chắc chắn muốn xóa nhân sự này?")) {
      deleteStaff(id);
    }
  };

  const handleResetPassword = (id) => {
    const newPass = prompt("Nhập mật khẩu mới:", "123456");
    if (newPass) {
      updatePassword(id, newPass);
      alert("Đã đặt lại mật khẩu!");
    }
  };

  const handlePromote = (id, currentRole) => {
    const roleOptions = [
        { val: 'staff', label: 'Nhân viên (Staff)' },
        { val: 'op_admin', label: 'Operational Admin (Vận hành)' },
        { val: 'reg_admin', label: 'Regulatory Admin (Quy chế)' },
        { val: 'chief_admin', label: 'Chief Admin (Tối cao)' }
    ];
    
    let roleListString = roleOptions.map((r, index) => `${index + 1}. ${r.label}`).join('\n');
    const choice = prompt(`Nhập số để bổ nhiệm chức vụ mới:\n${roleListString}`, "1");
    
    if (choice) {
        const selectedIndex = parseInt(choice) - 1;
        if (roleOptions[selectedIndex]) {
            promoteStaff(id, roleOptions[selectedIndex].val);
            alert(`Đã bổ nhiệm thành: ${roleOptions[selectedIndex].label}`);
        }
    }
  };

  const getRoleName = (role) => {
    switch(role) {
        case 'chief_admin': return 'Chief Admin';
        case 'reg_admin': return 'Regulatory Admin';
        case 'op_admin': return 'Operational Admin';
        default: return 'Staff';
    }
  };

  return (
    <div>
      <h2>Quản lý & Phân quyền Nhân sự</h2>
      
      {/* Form thêm mới - Chỉ hiện với Chief */}
      {isChief && (
        <form onSubmit={handleAdd} style={{ padding: '15px', background: '#e6f7ff', borderRadius: '8px', marginBottom: '20px', border: '1px solid #91d5ff' }}>
          <h4>Thêm nhân sự mới (Quyền Chief)</h4>
          <div style={{ display: 'flex', gap: '10px' }}>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required style={{ padding: '8px' }}/>
            <input placeholder="Tên đăng nhập" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} required style={{ padding: '8px' }}/>
            <input placeholder="Mật khẩu" type="password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required style={{ padding: '8px' }}/>
            <button type="submit" style={{ background: '#003366', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '4px', cursor: 'pointer' }}>Tạo mới</button>
          </div>
        </form>
      )}

      {/* Danh sách */}
      <table border="1" style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', background: 'white' }}>
        <thead style={{ background: '#eee' }}>
          <tr>
            <th style={{ padding: '10px' }}>Họ tên</th>
            <th style={{ padding: '10px' }}>Chức vụ (Role)</th>
            <th style={{ padding: '10px' }}>Trạng thái</th>
            <th style={{ padding: '10px' }}>Thao tác Quản trị</th>
          </tr>
        </thead>
        <tbody>
          {staffList.map(staff => (
            <tr key={staff.id} style={{ opacity: staff.status === 'suspended' ? 0.5 : 1 }}>
              <td style={{ padding: '10px' }}>
                {staff.name} <br/>
                <small style={{color: '#666'}}>@{staff.username}</small>
              </td>
              <td style={{ padding: '10px', fontWeight: 'bold', color: '#003366' }}>
                {getRoleName(staff.role)}
              </td>
              <td style={{ padding: '10px' }}>
                 {staff.status === 'active' 
                    ? <span style={{color: 'green', fontWeight: 'bold'}}>Đang hoạt động</span> 
                    : <span style={{color: 'red', fontWeight: 'bold'}}>Đã đình chỉ</span>}
              </td>
              <td style={{ padding: '10px' }}>
                {/* Chỉ Chief Admin mới thấy các nút này */}
                {isChief && (
                  <div style={{ display: 'flex', gap: '5px', flexWrap: 'wrap' }}>
                    <button onClick={() => handlePromote(staff.id, staff.role)} style={{ background: '#1890ff', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}>Bổ nhiệm</button>
                    
                    <button onClick={() => toggleStaffStatus(staff.id)} style={{ background: staff.status === 'active' ? '#fa8c16' : '#52c41a', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}>
                        {staff.status === 'active' ? 'Đình chỉ' : 'Kích hoạt'}
                    </button>
                    
                    <button onClick={() => handleResetPassword(staff.id)} style={{ background: '#ffc107', color: 'black', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}>Đổi MK</button>
                    
                    <button onClick={() => handleDelete(staff.id)} style={{ background: '#dc3545', color: 'white', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}>Xóa</button>
                  </div>
                )}
                {!isChief && <span style={{ color: '#999', fontStyle: 'italic' }}>Chỉ xem</span>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default StaffManager;
